const item = $input.first().json;
const execution = item.execution || {};
const workflow = item.workflow || {};
const error = execution.error || {};

// Try to find the chat_id from the failed execution's last input data
// n8n Error Trigger provides inputData from the failed execution
let chatId = null;
let userId = null;
let intentText = '';

// Walk through the execution data to find user context
const lastNodeData = execution.lastNodeExecuted;

// The inputData may contain Telegram context
if (execution.data && execution.data.startData) {
  const sd = execution.data.startData;
  if (sd.destinationNode) intentText = sd.destinationNode;
}

// Try to extract from execution metadata
const runData = (execution.data || {}).resultData || {};
const runNodes = (runData.runData || {});

// Walk all nodes to find chat_id
for (const [nodeName, nodeRuns] of Object.entries(runNodes)) {
  for (const run of nodeRuns) {
    const mainData = (run.data || {}).main || [];
    for (const output of mainData) {
      for (const item of (output || [])) {
        const j = item.json || {};
        if (j.chat_id && !chatId) chatId = j.chat_id;
        if (j.user_id && !userId) userId = j.user_id;
        if (j.message_text && !intentText) intentText = j.message_text;
        // Also check nested
        if (j.telegram_user_id && !chatId) chatId = j.telegram_user_id;
      }
    }
  }
}

const errorMsg = error.message || 'Unknown error';
const workflowName = workflow.name || 'StockPulse';
const execId = execution.id || 'unknown';

return [{
  json: {
    chat_id: chatId,
    user_id: userId,
    error_message: errorMsg,
    workflow_name: workflowName,
    execution_id: execId,
    user_message: intentText,
    has_user: !!chatId
  }
}];

